type Item = { type: string };
type Step = { op: "quote"; items: Array<Item> };
type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Array<Step>;
};
type QuoteResult = { premium: number };

const PROCESSING_FEE = 5;

// Per-item-type quoted premium (base + first-insurance surcharge, before fee).
// Hardcoded to the values exercised by current tests; will be derived as
// more rules are introduced.
const ITEM_PREMIUM_BEFORE_FEE: Record<string, number> = {
  sword: 110,
  amulet: 66,
};

const quoteItem = (item: Item): number => ITEM_PREMIUM_BEFORE_FEE[item.type];

const quoteStep = (step: Step): QuoteResult => {
  const itemsTotal = step.items.reduce((sum, item) => sum + quoteItem(item), 0);
  return { premium: itemsTotal + PROCESSING_FEE };
};

export const runScenario = (scenario: Scenario): { results: Array<QuoteResult> } => {
  return { results: scenario.steps.map(quoteStep) };
};
